    // Positive for high-complexity (many decision paths)
    public function branchy(int $x): int
    {
        $out = 0;
        if ($x > 0) { $out += 1; }
        if ($x > 1) { $out += 2; }
        if ($x > 2) { $out += 3; }
        if ($x > 3) { $out += 4; }
        if ($x > 4) { $out += 5; }
        if ($x > 5) { $out += 6; }
